public static int find_first_in_sorted(int[] arr, int x) {
    int lo = 0;
    int hi = arr.length - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] == x && (mid == 0 || arr[mid - 1] != x)) {
            return mid;
        } else if (arr[mid] >= x) {
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return -1;
}

